+    layout: params.layout ?? "v2",
+    title: "Model Picker",
+    detailLines: [formatCurrentModelLine(params.currentModel), `Default: ${defaultModel}`],
+    preRowText: pendingLine,
+    rows,
+    trailingRows: [buttonRow],
+  });
+}
