+      const threadId = resolveThreadBindingConversationIdFromBindingId({
+        accountId: params.accountId,
+        bindingId: input.bindingId,
+      });
+      if (!threadId) {
+        return [];
+      }
+      const removed = params.manager.unbindThread({
+        threadId,
+        reason: input.reason,
+      });
+      return removed ? [toRecord(removed)] : [];
+    },
+  };
